// Тестовые данные — сессия #27 (реальные ID из БД)
return [{ json: { body: {
  session_id:        27,
  idea_id:           37,
  voice_script_id:   25,
  video_prompt_id:   23,
  product_image_url: 'https://k-m-m.ru/api/media/public/images/1772881240516-b87125ce75aa7a87.jpg',
  artikul:           '',
  a2e_resolution:    '1080',
  subtitles_enabled: true,
  music_file_key:    '',
  music_volume:      0.15
} } }];

const input = $input.first().json;
const body = input.body || input;

if (!body.session_id) throw new Error('session_id is required');
if (!body.product_image_url) throw new Error('product_image_url is required');

return [{ json: {
  session_id:        Number(body.session_id),
  idea_id:           body.idea_id || 0,
  voice_script_id:   body.voice_script_id || 0,
  video_prompt_id:   body.video_prompt_id || 0,
  product_image_url: body.product_image_url,
  artikul:           body.artikul || '',
  video_type:        'a2e_product',
  a2e_resolution:    body.a2e_resolution || '1080',
  subtitles_enabled: body.subtitles_enabled !== false,
  music_file_key:    body.music_file_key || '',
  music_volume:      body.music_volume || 0.15
}}];

const dbRow  = $input.first().json;
const params = $('🔍 Валидация входа').first().json;

if (!dbRow.a2e_token) throw new Error('A2E token not found in app_settings (key: a2e_api_token)');

// Дефолтные значения (первый системный аватар + Sarah ttsRate:3 — надёжный голос)
const DEFAULT_AVATAR = '693bf9bd3caab0848a4cd107';
const DEFAULT_VOICE  = '6627e0b42f07d4f2a89a19fe'; // Sarah

return [{ json: {
  // Параметры сессии
  session_id:        params.session_id,
  idea_id:           params.idea_id,
  voice_script_id:   params.voice_script_id,
  video_prompt_id:   params.video_prompt_id,
  product_image_url: params.product_image_url || dbRow.db_product_image_url || '',
  artikul:           params.artikul || '',
  video_type:        params.video_type,
  a2e_resolution:    params.a2e_resolution || '1080',
  subtitles_enabled: params.subtitles_enabled,
  music_file_key:    params.music_file_key || '',
  music_volume:      params.music_volume || 0.15,
  // Данные из БД
  script_text:       dbRow.script_text || '',
  prompt_text:       dbRow.prompt_text || '',
  title:             dbRow.title || '',
  concept:           dbRow.concept || '',
  visual_description: dbRow.visual_description || '',
  // A2E параметры — несём в $json через весь воркфлоу
  a2e_token:         dbRow.a2e_token,
  a2e_avatar_id:     dbRow.a2e_avatar_id || DEFAULT_AVATAR,
  a2e_voice_id:      dbRow.a2e_voice_id  || DEFAULT_VOICE,
  // GPTunnel TTS параметры
  gptunnel_key:  dbRow.gptunnel_key || '',
  tts_voice_id:  dbRow.tts_voice_id || '65f4092eddc5862248a18111',
  site_url:      (dbRow.site_url || 'https://k-m-m.ru').replace(/\/+$/, '')
}}];

const https = require('https');
const ttsResp = $input.first().json;
const ctx = $('🔗 Объединение данных').first().json;

if (ttsResp.error) throw new Error('GPTunnel TTS ошибка: ' + JSON.stringify(ttsResp.error).substring(0, 300));
if (!ttsResp.data) throw new Error('GPTunnel TTS: пустой ответ. Ответ: ' + JSON.stringify(ttsResp).substring(0, 300));

const filename = `voice_${ctx.session_id}_a2e.mp3`;
const audioBuffer = Buffer.from(ttsResp.data, 'base64');

// Загружаем аудио на litterbox.catbox.moe (1ч хостинг — достаточно для A2E)
const audioUrl = await new Promise((resolve, reject) => {
  const boundary = 'lb' + Date.now();
  const parts = [
    '--' + boundary + '\r\nContent-Disposition: form-data; name="reqtype"\r\n\r\nfileupload',
    '--' + boundary + '\r\nContent-Disposition: form-data; name="time"\r\n\r\n1h',
    '--' + boundary + '\r\nContent-Disposition: form-data; name="fileToUpload"; filename="' + filename + '"\r\nContent-Type: audio/mpeg\r\n\r\n'
  ];
  const body = Buffer.concat([
    Buffer.from(parts.join('\r\n') + '\r\n'),
    audioBuffer,
    Buffer.from('\r\n--' + boundary + '--\r\n')
  ]);
  const req = https.request({
    hostname: 'litterbox.catbox.moe',
    path: '/resources/internals/api.php',
    method: 'POST',
    headers: {
      'Content-Type': 'multipart/form-data; boundary=' + boundary,
      'Content-Length': body.length
    }
  }, (res) => {
    const chunks = [];
    res.on('data', c => chunks.push(c));
    res.on('end', () => {
      const url = Buffer.concat(chunks).toString().trim();
      if (url.startsWith('https://')) resolve(url);
      else reject(new Error('Litterbox upload failed: ' + url.substring(0, 200)));
    });
  });
  req.on('error', reject);
  req.setTimeout(30000, () => reject(new Error('Litterbox upload timeout — проверьте интернет-соединение n8n')));
  req.write(body);
  req.end();
});

return [{ json: { ...ctx, audio_url: audioUrl } }];

const resp = $input.first().json;

// Сначала проверяем — вдруг A2E вернул ошибку
if (resp.code !== undefined && resp.code !== 0) {
  throw new Error('A2E API error ' + resp.code + ': ' + (resp.msg || resp.message || JSON.stringify(resp).substring(0, 300)));
}

// Найти узел Объединение данных независимо от суффикса '1' при повторном импорте
const mergeNode = $('🔗 Объединение данных') || $('🔗 Объединение данных1');
const ctx = mergeNode.first().json;

// Перебираем все возможные поля ответа a2e.ai
const videoId =
  (resp.data && (resp.data._id || resp.data.id || resp.data.video_id || resp.data.task_id || resp.data.job_id)) ||
  resp._id || resp.id || resp.video_id || resp.task_id || resp.job_id || resp.taskId || resp.jobId;

if (!videoId) throw new Error('A2E: no video_id in response. Body: ' + JSON.stringify(resp).substring(0, 600));

return [{ json: {
  video_id:   videoId,
  session_id: ctx.session_id,
  a2e_token:  ctx.a2e_token,
  poll_count: 0
}}];

const resp = $input.first().json;
// Состояние цикла несём через $json (Wait нода передаёт его)
const prev = $input.first().json;

// video_id/session_id/token — из предыдущей итерации через Wait
// На первой итерации они приходят из restore-poll-data
const videoId   = prev.video_id;
const sessionId = prev.session_id;
const token     = prev.a2e_token;
const pollCount = (prev.poll_count || 0) + 1;

// Разбираем ответ API
const data  = resp.data || resp;
const items = Array.isArray(data) ? data : [data];
const item  = items[0] || {};

const status   = (item.status || item.state || '').toLowerCase();
const videoUrl = item.result || item.video_url || item.url || item.output_url || item.video || '';

if (status === 'success' || status === 'completed' || status === 'done' || videoUrl) {
  if (!videoUrl) throw new Error('A2E status=' + status + ' but no video URL. Response: ' + JSON.stringify(item).substring(0, 300));
  return [{ json: { session_id: sessionId, raw_video_url: videoUrl, status: 'ready', poll_count: pollCount } }];
}

if (status === 'failed' || status === 'error') {
  throw new Error('A2E generation failed: ' + JSON.stringify(item).substring(0, 300));
}

if (pollCount > 90) throw new Error('A2E timeout: 90 polls exceeded (30 min)');

// Продолжаем поллинг — передаём все нужные поля через Wait ноду
return [{ json: { video_id: videoId, session_id: sessionId, a2e_token: token, poll_count: pollCount, status: 'pending' } }];
